#include <bits/stdc++.h>
using namespace std;
string s;
int a = 1;//计数器，因为0号位跳过所以从1开始。 
int main()
{
	cin >> s;
	for (int i = 1; i < s.length(); i++)//不遍历0号位。 
		{
			if (s[i] != s[i - 1])
				{
					cout << a << s[i - 1];
					a = 0;
				}
			a++;	
		}
	cout << a << s[s.length() - 1];	//最后输出最后一组数据。 
	return 0;//AC！ 
}
